import { useForm } from 'react-hook-form';

function CadastroForm() {
  const {
    register,
    handleSubmit,
    formState: { errors }
  } = useForm();

  const onSubmit = (data) => {
    console.log(data);
    // { nome: 'Maria', email: 'maria@email.com' }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <input {...register('nome', { required: 'Nome é obrigatório' })} />
      {errors.nome && <span>{errors.nome.message}</span>}

      <input {...register('email', {
        required: 'Email é obrigatório',
        pattern: {
          value: /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i,
          message: 'Email inválido'
        }
      })} />
      {errors.email && <span>{errors.email.message}</span>}

      <button type="submit">Cadastrar</button>
    </form>
  );
}

// register aceita regras de validação como segundo argumento
register('senha', {
  required: 'Senha é obrigatória',
  minLength: {
    value: 6,
    message: 'Mínimo de 6 caracteres'
  }
})

// Equivale a gerar automaticamente:
// { onChange, onBlur, ref, name: 'senha' }

// handleSubmit valida antes de chamar onSubmit
<form onSubmit={handleSubmit(onSubmit)}>

// Se a validação falhar, onSubmit NÃO é chamada.
// Os erros ficam disponíveis em formState.errors.

// Você pode ter um handler de erro separado:
handleSubmit(onValid, onInvalid)
